     #[tokio::test]
     async fn index_shows_register_and_login_links_for_unauthenticated_visitor() {
         let app = spawn_app().await;
         let client = reqwest::Client::new();
         let response = client.get(format!("{}/", &app.address)).send().await.expect("Failed");
         assert_eq!(response.status().as_u16(), 200);
         let body = response.text().await.unwrap();
         assert!(body.contains("href=\"/register\""), "Missing link to /register");
         assert!(body.contains("Create account"), "Missing 'Create account' link text");
         assert!(body.contains("href=\"/login\""), "Missing link to /login");
         assert!(body.contains("Sign in"), "Missing 'Sign in' link text");
     }

     #[tokio::test]
     async fn index_redirects_authenticated_user_to_todos() {
         let app = spawn_app().await;
         let client = register_and_login(&app.address, "index@example.com", "securepassword123").await;
         let response = client.get(format!("{}/", &app.address)).send().await.expect("Failed");
         assert_eq!(response.status().as_u16(), 303, "Authenticated user should be redirected");
         let location = response.headers().get("location").expect("Missing Location header").to_str().unwrap();
         assert_eq!(location, "/todos", "Should redirect to /todos");
     }
     ```

