     import { test, expect, Page } from "@playwright/test";

     const testEmail = `e2e-${Date.now()}@example.com`;
     const testPassword = "securepassword123";

     async function fillRegistrationForm(page: Page, email: string, password: string) {
       await page.waitForLoadState("networkidle");
       await page.getByLabel("Email").fill(email);
       await page.getByLabel("Password", { exact: true }).fill(password);
       const confirmCount = await page.getByLabel("Confirm password").count();
       if (confirmCount > 0) {
         const isVisible = await page.getByLabel("Confirm password").isVisible();
         if (isVisible) { await page.getByLabel("Confirm password").fill(password); }
       }
       await page.getByRole("button", { name: "Create account" }).click();
     }
     // ... 3 test cases (visitor sees links, full journey, authenticated redirect)
     ```

